SELECT
    t1.setting_id,t1.dept_id,t2.dept_name,t1.spu_no,t3.name,t1.quanintiy,t1.in_quanintiy,t1.ready_quanintiy,t1.specifications,
    t1.self_quanintiy,t1.setting_quanintiy,t1.create_time,t1.last_modify_time
FROM
    store_sale_setting t1,
    sys_dept t2,
    store_goods_spu t3

    t1.dept_id = t2.dept_id AND t1.spu_no = t3.spu_no AND t1.status = '1'

        and t1.dept_id IN

            #{deptId}


     and t1.dept_id = #{deptId}
     and t1.spu_no = #{spuNo}
     and (t1.spu_no like concat('%', #{spuName}, '%') or t3.name like concat('%', #{spuName}, '%') )
     and quanintiy = #{quanintiy}
     and in_quanintiy = #{inQuanintiy}
     and ready_quanintiy = #{readyQuanintiy}
     and specifications = #{specifications}
     and setting_quanintiy = #{settingQuanintiy}
     and t1.create_time = #{createTime}
     and t1.last_modify_time = #{lastModifyTime}
    and t1.create_time >= #{createTimeStart}
    and t1.create_time <= #{createTimeEnd}

ORDER BY t1.last_modify_time DESC

